import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

// Knowledge base about Roy
const ROY_KNOWLEDGE = {
  personal: {
    name: "Roy Dinh",
    education: "Computer Science student",
    interests: [
      "Software Engineering",
      "Artificial Intelligence",
      "Web Development",
      "Problem Solving"
    ],
    skills: {
      languages: ["Python", "JavaScript", "Java", "C++", "C", "SQL", "x86-64 Assembly", "HTML/CSS"],
      frontend: ["React"],
      backend: ["Node.js", "Express.js", "Flask"],
      databases: ["PostgreSQL"],
      tools: ["Git", "Docker", "VS Code", "Jupyter Notebook"]
    },
    projects: [
      "Portfolio website with AI integration",
      "Various web development projects",
      "AI and machine learning experiments"
    ]
  }
};

// Basic Computer Science Knowledge
const CS_KNOWLEDGE = {
  dataStructures: {
    arrays: "Linear data structure that stores elements at contiguous memory locations.",
    linkedLists: "Linear data structure where elements are stored in nodes, and each node points to the next node.",
    stacks: "LIFO (Last In First Out) data structure.",
    queues: "FIFO (First In First Out) data structure.",
    trees: "Hierarchical data structure with a root node and child nodes.",
    graphs: "Non-linear data structure consisting of nodes and edges."
  },
  algorithms: {
    sorting: ["Bubble Sort", "Quick Sort", "Merge Sort", "Insertion Sort"],
    searching: ["Linear Search", "Binary Search"],
    complexity: {
      "O(1)": "Constant time",
      "O(log n)": "Logarithmic time",
      "O(n)": "Linear time",
      "O(n log n)": "Linearithmic time",
      "O(n²)": "Quadratic time"
    }
  },
  concepts: {
    oop: "Object-Oriented Programming principles: Encapsulation, Inheritance, Polymorphism, Abstraction",
    databases: "SQL vs NoSQL, ACID properties, Normalization",
    networking: "TCP/IP, HTTP/HTTPS, DNS, REST APIs",
    security: "Authentication, Authorization, Encryption, Hashing"
  }
};

const RoyAI = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([
    {
      text: "Hi! I'm RoyAI, a digital version of Roy. I can tell you about Roy's skills, experience, and interests. I also know basic computer science concepts and can do simple math. What would you like to know?",
      sender: 'ai'
    }
  ]);
  const [input, setInput] = useState('');
  const messagesEndRef = useRef(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const evaluateMathExpression = (expression) => {
    try {
      // Basic safety check - only allow numbers and basic operators
      if (!/^[0-9+\-*/().\s]+$/.test(expression)) {
        return null;
      }
      return eval(expression);
    } catch (e) {
      return null;
    }
  };

  const generateResponse = (input) => {
    const lowerInput = input.toLowerCase();

    // Check for math expressions
    const mathResult = evaluateMathExpression(input);
    if (mathResult !== null) {
      return `The result is: ${mathResult}`;
    }

    // Personal information responses
    if (lowerInput.includes('skill') || lowerInput.includes('language')) {
      return `I'm proficient in ${ROY_KNOWLEDGE.personal.skills.languages.join(', ')}. I also work with ${ROY_KNOWLEDGE.personal.skills.frontend.join(', ')}, ${ROY_KNOWLEDGE.personal.skills.backend.join(', ')}, and ${ROY_KNOWLEDGE.personal.skills.databases.join(', ')}.`;
    }

    if (lowerInput.includes('experience') || lowerInput.includes('work')) {
      return "I'm currently focused on Software Engineering with a specialization in Artificial Intelligence. I'm building my portfolio and looking for opportunities to apply my skills.";
    }

    if (lowerInput.includes('interest') || lowerInput.includes('hobby')) {
      return `I'm passionate about ${ROY_KNOWLEDGE.personal.interests.join(', ')}. I enjoy working on projects that combine these interests and am always eager to learn new technologies.`;
    }

    // Computer Science knowledge responses
    if (lowerInput.includes('data structure')) {
      const structure = Object.keys(CS_KNOWLEDGE.dataStructures).find(key => 
        lowerInput.includes(key)
      );
      if (structure) {
        return CS_KNOWLEDGE.dataStructures[structure];
      }
      return "I know about various data structures including arrays, linked lists, stacks, queues, trees, and graphs. Which one would you like to learn about?";
    }

    if (lowerInput.includes('algorithm')) {
      if (lowerInput.includes('sort')) {
        return `Common sorting algorithms include: ${CS_KNOWLEDGE.algorithms.sorting.join(', ')}.`;
      }
      if (lowerInput.includes('search')) {
        return `Common searching algorithms include: ${CS_KNOWLEDGE.algorithms.searching.join(', ')}.`;
      }
      return "I can tell you about sorting algorithms, searching algorithms, and their time complexities. What would you like to know?";
    }

    if (lowerInput.includes('complexity') || lowerInput.includes('big o')) {
      return "I understand time complexity notations like O(1), O(log n), O(n), O(n log n), and O(n²). Which one would you like me to explain?";
    }

    if (lowerInput.includes('oop') || lowerInput.includes('object oriented')) {
      return CS_KNOWLEDGE.concepts.oop;
    }

    if (lowerInput.includes('database')) {
      return CS_KNOWLEDGE.concepts.databases;
    }

    if (lowerInput.includes('network') || lowerInput.includes('api')) {
      return CS_KNOWLEDGE.concepts.networking;
    }

    if (lowerInput.includes('security')) {
      return CS_KNOWLEDGE.concepts.security;
    }

    return "I'm RoyAI, a digital representation of Roy. I can tell you about Roy's skills, experience, and interests. I also know basic computer science concepts and can do simple math. What would you like to know?";
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!input.trim()) return;

    // Add user message
    const userMessage = { text: input, sender: 'user' };
    setMessages(prev => [...prev, userMessage]);
    setInput('');

    // Simulate AI thinking
    const thinkingMessage = { text: "Thinking...", sender: 'ai', isThinking: true };
    setMessages(prev => [...prev, thinkingMessage]);

    // Generate response
    setTimeout(() => {
      setMessages(prev => prev.filter(msg => !msg.isThinking));
      const aiResponse = generateResponse(input);
      setMessages(prev => [...prev, { text: aiResponse, sender: 'ai' }]);
    }, 1000);
  };

  return (
    <>
      <motion.button
        className="roy-ai-button"
        onClick={() => setIsOpen(!isOpen)}
        whileHover={{ scale: 1.05 }}
        whileTap={{ scale: 0.95 }}
      >
        {isOpen ? 'Close RoyAI' : 'Chat with RoyAI'}
      </motion.button>

      <AnimatePresence>
        {isOpen && (
          <motion.div
            className="chat-window"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 20 }}
            transition={{ duration: 0.3 }}
          >
            <div className="chat-messages">
              {messages.map((message, index) => (
                <motion.div
                  key={index}
                  className={`message ${message.sender}`}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.3 }}
                >
                  {message.text}
                </motion.div>
              ))}
              <div ref={messagesEndRef} />
            </div>
            <form onSubmit={handleSubmit} className="chat-input-form">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="Ask me anything..."
                className="chat-input"
              />
              <button type="submit" className="send-button">
                Send
              </button>
            </form>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

export default RoyAI;
